function showPosts(t){let s="";t&&0!==t.length||(s="<h1>No results</h1>"),t.forEach((t=>{s+=`<div class="single-post-area style-2">\n    <div class="row align-items-center">\n        <div class="col-12 col-md-6">\n            <div class="post-thumbnail">\n                <img src="/img/${t.thumbnail}" alt="${t.title}" class="img-fluid">\n            </div>\n        </div>\n        <div class="col-12 col-md-6">\n            <div class="post-content mt-0">\n                <a href="/posts/${t.file}" class="post-title post-link mb-2">${t.title}</a>\n                <div class="post-meta d-flex align-items-center mb-2">\n                    <span class="post-author">${t.author.name}</span>\n                    <i class="far fa-circle" aria-hidden="true"></i>\n                    <span class="post-date">${t.postDate}</span>\n                </div>\n                <p class="mb-2 post-excerpt">${t.excerpt}</p>\n            </div>\n        </div>\n    </div>\n</div>`})),document.getElementById("post-container").innerHTML=s}const urlParams=new URLSearchParams(window.location.search),term=urlParams.get("search");if(term){document.getElementById("search").value=term;const t=term.toLowerCase();fetch("/js/search.json").then((t=>t.json())).then((s=>{term.startsWith("tag:")?showPosts(s.filter((s=>s.tags.includes(t.replace("tag:",""))))):showPosts(s.filter((s=>s.title.toLowerCase().includes(t)||s.body.includes(t))))}))}function onLinkClick(t){window.location.href=t.target.href}[...document.querySelectorAll(".pager .post-title")].forEach((t=>t.addEventListener("click",onLinkClick)));